namespace sv_e7a610dc61274dfb8bc55ca467dc6a71.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@rendermode InteractiveServer

<div class="message-input">
    <textarea @bind="text"
              @bind:event="oninput"
              placeholder="@Placeholder"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="btn-send" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string text = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var message = text.Trim();
        text = "";
        await OnSubmit.InvokeAsync(message);
    }
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 0.5rem 0.75rem;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #4a76a8;
}

.btn-send {
    align-self: flex-end;
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 6px;
    background: #4a76a8;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-send:hover:not(:disabled) {
    background: #3b6190;
}

.btn-send:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@rendermode InteractiveServer

<div class="message-item"
     @onmouseenter="ShowActions"
     @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (Thread is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            💬 @Thread.ReplyCount @(Thread.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">💬</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <button @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? Thread { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ShowActions() => showActions = true;

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    internal static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff switch
        {
            { TotalMinutes: < 1 } => "just now",
            { TotalMinutes: < 60 } => $"{(int)diff.TotalMinutes} min ago",
            { TotalHours: < 24 } => $"{(int)diff.TotalHours}h ago",
            { TotalDays: < 7 } => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.5;
    color: #1d1c1d;
    white-space: pre-wrap;
}

.reactions {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.35rem;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f4f8;
    font-size: 0.82rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dce8f3;
    border-color: #a0bdd8;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    padding: 0.15rem 0.4rem;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 0.25rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.15rem;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    border: none;
    background: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #e8e8e8;
}

.emoji-picker {
    position: absolute;
    right: 0.5rem;
    top: 2.2rem;
    display: flex;
    gap: 0.2rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

.emoji-picker button {
    border: none;
    background: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 0.2rem 0.3rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-picker button:hover {
    background: #f0f0f0;
}

@rendermode InteractiveServer

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-row">
                    <div class="channel-info">
                        <span class="channel-name"># @channel.Name</span>
                        <span class="channel-desc">@TruncateDescription(channel.Description)</span>
                    </div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? string.Concat(description.AsSpan(0, 37), "...") : description;
    }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-title {
    padding: 1rem 1rem 0.5rem;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    margin: 0;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 0.4rem 1rem;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 0.5rem;
    transition: background 0.1s;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.channel-info {
    display: flex;
    flex-direction: column;
    min-width: 0;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #ab9bab;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: rgba(255,255,255,0.7);
}

.unread-badge {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 1.3rem;
    height: 1.3rem;
    padding: 0 0.35rem;
    border-radius: 10px;
    background: #e01e5a;
    color: #fff;
    font-size: 0.72rem;
    font-weight: 700;
}

@rendermode InteractiveServer

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <span class="root-author">@RootMessage.Author</span>
            <p class="root-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-timestamp">@MessageItem.FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
