toolArgs.file_text:
.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.5;
    color: #1d1c1d;
    white-space: pre-wrap;
}

.reactions {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.35rem;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f4f8;
    font-size: 0.82rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dce8f3;
    border-color: #a0bdd8;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    padding: 0.15rem 0.4rem;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 0.25rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.15rem;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    border: none;
    background: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #e8e8e8;
}

.emoji-picker {
    position: absolute;
    right: 0.5rem;
    top: 2.2rem;
    display: flex;
    gap: 0.2rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

.emoji-picker button {
    border: none;
    background: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 0.2rem 0.3rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-picker button:hover {
    background: #f0f0f0;
}

