toolArgs.file_text:
@rendermode InteractiveServer

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-row">
                    <div class="channel-info">
                        <span class="channel-name"># @channel.Name</span>
                        <span class="channel-desc">@TruncateDescription(channel.Description)</span>
                    </div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? string.Concat(description.AsSpan(0, 37), "...") : description;
    }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-title {
    padding: 1rem 1rem 0.5rem;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    margin: 0;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 0.4rem 1rem;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 0.5rem;
    transition: background 0.1s;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.channel-info {
    display: flex;
    flex-direction: column;
    min-width: 0;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 0.75rem;
    color: #ab9bab;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-desc {
    color: rgba(255,255,255,0.7);
}

.unread-badge {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 1.3rem;
    height: 1.3rem;
    padding: 0 0.35rem;
    border-radius: 10px;
    background: #e01e5a;
    color: #fff;
    font-size: 0.72rem;
    font-weight: 700;
}

