@rendermode InteractiveServer

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <span class="root-author">@RootMessage.Author</span>
            <p class="root-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-timestamp">@MessageItem.FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply..." ButtonText="Reply" OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #ddd;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    border: none;
    background: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 0.2rem 0.4rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.close-btn:hover {
    background: #e8e8e8;
    color: #333;
}

.thread-root {
    padding: 0.75rem 1rem;
    background: #f8f8f8;
    border-bottom: 1px solid #e0e0e0;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.root-content {
    margin: 0.25rem 0 0;
    font-size: 0.9rem;
    line-height: 1.4;
    color: #333;
    white-space: pre-wrap;
}

.thread-divider {
    padding: 0.4rem 1rem;
    font-size: 0.75rem;
    color: #888;
    border-bottom: 1px solid #e8e8e8;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.thread-reply {
    padding: 0.4rem 1rem;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 0.4rem;
    margin-bottom: 0.1rem;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-timestamp {
    font-size: 0.72rem;
    color: #888;
}

.reply-content {
    font-size: 0.88rem;
    line-height: 1.4;
    color: #1d1c1d;
    white-space: pre-wrap;
}

