arguments.file_text:
export function observeScrollTop(sentinel, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetHelper.invokeMethodAsync('OnScrolledToTop');
        }
    }, { threshold: 0.1 });
    observer.observe(sentinel);
    return observer;
}

export function disposeObserver(observer) {
    observer.disconnect();
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-container">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-area @(isThreadOpen ? "with-thread" : "full-width")">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h2># @selectedChannel.Name</h2>
                <p>@selectedChannel.Description</p>
            </div>

            <div class="message-list" @ref="messageListRef">
                <div @ref="scrollSentinelRef" class="scroll-sentinel">
                    @if (isLoadingMore)
                    {
                        <div class="loading-indicator">Loading older messages…</div>
                    }
                </div>

                @foreach (var msg in messages)
                {
                    <MessageItem Message="msg"
                                 Thread="threadSummaries.GetValueOrDefault(msg.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="AddReaction" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")" OnSubmit="SendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen)
    {
        <div class="thread-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private int selectedChannelId;
    private Channel? selectedChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private bool isLoadingMore;
    private int messageSkip;
    private bool hasMoreMessages = true;
    private const int PageSize = 50;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private ElementReference messageListRef;
    private ElementReference scrollSentinelRef;
    private IJSObjectReference? jsModule;
    private IJSObjectReference? scrollObserver;
    private DotNetObjectReference<Chat>? dotNetRef;
    private bool isFirstLoad = true;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./Components/Pages/Chat.razor.js");
            dotNetRef = DotNetObjectReference.Create(this);

            if (scrollSentinelRef.Id is not null)
            {
                scrollObserver = await jsModule.InvokeAsync<IJSObjectReference>(
                    "observeScrollTop", scrollSentinelRef, dotNetRef);
            }
        }

        if (isFirstLoad && messages.Count > 0)
        {
            isFirstLoad = false;
            if (jsModule is not null)
            {
                await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
            }
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (isLoadingMore || !hasMoreMessages || selectedChannel is null) return;

        isLoadingMore = true;
        await InvokeAsync(StateHasChanged);

        var older = await ChatService.GetMessagesAsync(selectedChannelId, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
            BuildThreadSummaries();
        }

        if (older.Count < PageSize)
        {
            hasMoreMessages = false;
        }

        isLoadingMore = false;
        await InvokeAsync(StateHasChanged);
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.Find(c => c.Id == channelId);
        messageSkip = 0;
        hasMoreMessages = true;
        isFirstLoad = true;

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messageSkip = messages.Count;

        if (messages.Count < PageSize)
        {
            hasMoreMessages = false;
        }

        await ChatService.MarkChannelReadAsync(channelId);
        BuildThreadSummaries();
        CloseThread();

        // Update the channel's unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);

        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.Find(m => m.Id == messageId);
        if (threadRootMessage is null) return;
        threadReplies = await ChatService.GetThreadAsync(messageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update the thread summary so the main message list reflects the new reply count
        var rootId = threadRootMessage.Id;
        threadSummaries[rootId] = new ThreadSummary(rootId,
            threadReplies.Count,
            reply.SentAt);
    }

    private async Task AddReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Refresh messages to reflect updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannelId, 0, messageSkip);
            BuildThreadSummaries();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (scrollObserver is not null)
        {
            try
            {
                if (jsModule is not null)
                {
                    await jsModule.InvokeVoidAsync("disposeObserver", scrollObserver);
                }
                await scrollObserver.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }

        dotNetRef?.Dispose();

        if (jsModule is not null)
        {
            try { await jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

