+        var older = await ChatService.GetMessagesAsync(selectedChannelId, messageSkip, PageSize);
+        if (older.Count > 0)
+        {
+            messages.InsertRange(0, older);
+            messageSkip += older.Count;
+            BuildThreadSummaries();
+        }
+
+        if (older.Count < PageSize)
+        {
+            hasMoreMessages = false;
+        }
+
+        isLoadingMore = false;
+        await InvokeAsync(StateHasChanged);
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        selectedChannelId = channelId;
+        selectedChannel = channels.Find(c => c.Id == channelId);
