.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    background: #fff;
}

.sidebar-container {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-area {
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.main-area.full-width {
    flex: 1;
}

.main-area.with-thread {
    flex: 0 0 55%;
}

.channel-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1d1c1d;
}

.channel-header p {
    margin: 0.15rem 0 0;
    font-size: 0.82rem;
    color: #666;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.scroll-sentinel {
    height: 1px;
}

.loading-indicator {
    text-align: center;
    padding: 0.75rem;
    font-size: 0.85rem;
    color: #888;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1rem;
}

.thread-container {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

